class ShortestJobFirst {
    // Method to calculate average waiting time
    calculateAverageWaitTime(jobs) {
        // Sort jobs in ascending order (Shortest Job First)
        jobs.sort((a, b) => a - b);

        let waitTime = 0;   // Stores cumulative waiting time
        let totalTime = 0;  // Tracks elapsed execution time
        let n = jobs.length; // Number of jobs

        // Iterate through each job
        for (let i = 0; i < n; i++) {
            waitTime += totalTime;   // Add current total time to waiting time
            totalTime += jobs[i];    // Execute current job
        }

        // Return the average waiting time
        return waitTime / n;
    }
}

